module.render:
const esc = (s) => String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const raw = (sections[0] || '').toString();
const parts = raw.split('+').map(function (k) { return k.trim(); }).filter(function (k) { return k.length > 0; });
let html = '<span class="mdp-mod-shortcut">';
parts.forEach(function (key, index) {
  if (index > 0) html += '<span class="shortcut-plus">+</span>';
  html += '<kbd class="shortcut-key">' + esc(key) + '</kbd>';
});
html += '</span>';
return html;
